@Composable
fun CountryItem(country: Country, modifier: Modifier = Modifier) {
    val expanded = remember { mutableStateOf(false) }
    Card(modifier = modifier.padding(dimensionResource(R.dimen.padding_small)).clickable { expanded.value = !expanded.value }) {
